// Reset cross-seed dedup tracker at start of each execution
const staticData = $getWorkflowStaticData('global');
staticData.seenUsernames = {};

// Flatten all 4 columns into individual rows with clean usernames
const allSeeds = [];
const seenUsernames = new Set();

function extractUsername(url) {
  if (!url || typeof url !== 'string') return '';
  let clean = url.trim()
    .replace(/^https?:\/\//i, '')
    .replace(/^www\./i, '')
    .replace(/^instagram\.com\//i, '')
    .replace(/\/$/g, '')
    .replace(/@/g, '');
  if (clean.includes('/')) {
    const parts = clean.split('/').filter(p => p.length > 0);
    clean = parts[parts.length - 1];
  }
  return clean.toLowerCase();
}

const columnMap = {
  'Individual Collector': 'individual_collector',
  'Collector/Page': 'collector_page',
  'Dealer': 'dealer',
  'Designer': 'designer',
  'Auctioneer': 'auctioneer',
  'Celebrities': 'celebrities',
  'Media': 'media',
  'Auction House': 'auction_house',
  'Other Luxury Goods': 'other_luxury_goods',
  'Collector\'s Club': 'collectors_club'
};

for (const row of $input.all()) {
  for (const [col, seedType] of Object.entries(columnMap)) {
    const rawValue = row.json[col];
    if (!rawValue) continue;
    const username = extractUsername(rawValue);
    if (!username || seenUsernames.has(username)) continue;
    seenUsernames.add(username);
    allSeeds.push({
      json: { username, seed_type: seedType, original_url: rawValue }
    });
  }
}

return allSeeds;

// Check if the Apify scraper returned a valid result
const result = $json;

// Check for errors or missing dataset ID
if (!result || !result.data || !result.data.defaultDatasetId) {
  // Scraper failed (private account, API error, etc.) - skip to next seed
  return [{ json: { _skip: true, _error: 'No dataset returned - likely private account or scraper error' } }];
}

// Check if the run actually succeeded
if (result.data.status === 'FAILED' || result.data.status === 'ABORTED') {
  return [{ json: { _skip: true, _error: `Scraper run ${result.data.status}` } }];
}

// Valid result - pass through the dataset ID
return [{ json: { datasetId: result.data.defaultDatasetId, _skip: false } }];

// Fetch follower dataset - always return at least one item so flow never dies
const datasetId = $json.datasetId;
const token = '{{ $env.APIFY_TOKEN }}';

try {
  const response = await fetch(`https://api.apify.com/v2/datasets/${datasetId}/items?token=${token}&format=json`);
  if (!response.ok) {
    return [{ json: { _skip: true, _error: `Dataset fetch failed: ${response.status}` } }];
  }
  const data = await response.json();
  if (!Array.isArray(data) || data.length === 0) {
    return [{ json: { _skip: true, _error: 'Empty dataset - no followers found' } }];
  }
  // Ensure each item is a proper object for n8n
  return data.map(item => ({ json: typeof item === 'object' && item !== null && !Array.isArray(item) ? item : { _raw: item } }));
} catch (e) {
  return [{ json: { _skip: true, _error: `Fetch error: ${e.message}` } }];
}

// Filter out private accounts, normalize, and deduplicate across seeds
// Use static data to track all processed usernames across loop iterations
const staticData = $getWorkflowStaticData('global');
if (!staticData.seenUsernames) staticData.seenUsernames = {};
const globalSeen = staticData.seenUsernames;

const items = $input.all();
let seedUsername = 'unknown';
let seedType = 'unknown';
try {
  const seedItem = $('Process Seeds').first();
  seedUsername = seedItem.json.username || 'unknown';
  seedType = seedItem.json.seed_type || 'unknown';
} catch (e) {
  // paired item unavailable, use defaults
}

// Handle error responses from HTTP nodes (private account, API error, etc.)
const firstItem = items[0]?.json || {};
if (!items || items.length === 0 || firstItem.error || firstItem.statusCode >= 400 || !firstItem.username) {
  return [{ json: { _skip: true } }];
}

const followers = [];
const batchSeen = new Set();

for (const item of items) {
  const p = item.json;
  const username = (p.username || '').toLowerCase();
  if (!username || batchSeen.has(username)) continue;
  if (p.is_private) continue;
  // Cross-seed dedup: skip if already processed from a previous seed
  if (globalSeen[username]) continue;
  batchSeen.add(username);
  globalSeen[username] = true;
  followers.push({
    json: {
      username: p.username,
      full_name: p.full_name || '',
      is_verified: p.is_verified || false,
      seed_account: seedUsername,
      seed_type: seedType
    }
  });
}

return followers.length > 0 ? followers.slice(0, 5) : [{ json: { _skip: true } }];

// Aggregate all follower usernames into a single item for one API call
const usernames = $input.all().map(i => i.json.username).filter(u => u);
return [{ json: { usernames } }];

// Check if the profile scraper returned a valid result
const result = $json;
if (!result || !result.data || !result.data.defaultDatasetId) {
  return [{ json: { _skip: true, _error: 'No dataset returned from profile scraper' } }];
}
if (result.data.status === 'FAILED' || result.data.status === 'ABORTED') {
  return [{ json: { _skip: true, _error: `Profile scraper ${result.data.status}` } }];
}
return [{ json: { datasetId: result.data.defaultDatasetId, _skip: false } }];

// Fetch profile dataset - always return at least one item so flow never dies
const datasetId = $json.datasetId;
const token = '{{ $env.APIFY_TOKEN }}';

try {
  const response = await fetch(`https://api.apify.com/v2/datasets/${datasetId}/items?token=${token}&format=json`);
  if (!response.ok) {
    return [{ json: { _empty: true, _error: `Dataset fetch failed: ${response.status}` } }];
  }
  const data = await response.json();
  if (!Array.isArray(data) || data.length === 0) {
    return [{ json: { _empty: true, _error: 'Empty dataset - no profiles returned' } }];
  }
  // Ensure each item is a proper object for n8n
  return data.map(item => ({ json: typeof item === 'object' && item !== null && !Array.isArray(item) ? item : { _raw: item } }));
} catch (e) {
  return [{ json: { _empty: true, _error: `Fetch error: ${e.message}` } }];
}

// Enrich with profile details from apify/instagram-profile-scraper
// Build a lookup map from Filter Public Accounts to get seed info per username
const seedLookup = {};
try {
  const filterItems = $('Filter Public Accounts').all();
  for (const fi of filterItems) {
    if (fi.json.username) {
      seedLookup[fi.json.username.toLowerCase()] = {
        seed_account: fi.json.seed_account || 'unknown',
        seed_type: fi.json.seed_type || 'unknown'
      };
    }
  }
} catch (e) {
  try {
    const seedItem = $('Process Seeds').first();
    seedLookup['_default'] = {
      seed_account: seedItem.json.username || 'unknown',
      seed_type: seedItem.json.seed_type || 'unknown'
    };
  } catch (e2) {
    seedLookup['_default'] = { seed_account: 'unknown', seed_type: 'unknown' };
  }
}

const defaultSeed = seedLookup['_default'] || Object.values(seedLookup)[0] || { seed_account: 'unknown', seed_type: 'unknown' };
const enriched = [];

for (const item of $input.all()) {
  const p = item.json;
  if (!p.username) continue;

  const seed = seedLookup[p.username.toLowerCase()] || defaultSeed;

  // Extract comprehensive data from recent posts
  let recentCaptions = '';
  let hashtags = '';
  let postUrls = '';
  let postLikes = '';
  let postComments = '';
  let postDates = '';
  let postLocations = '';
  let postTypes = '';
  let allMentions = new Set();
  let totalLikes = 0;
  let totalComments = 0;
  let postCount = 0;
  let imageUrlsList = [];
  let videoUrlsList = [];

  if (p.latestPosts && Array.isArray(p.latestPosts)) {
    const posts = p.latestPosts;
    const captions = [];
    const urls = [];
    const likes = [];
    const comments = [];
    const dates = [];
    const locations = [];
    const types = [];

    for (const post of posts) {
      const caption = (post.caption || '').substring(0, 300);
      if (caption) captions.push(caption);
      urls.push(post.url || post.shortCode ? `https://instagram.com/p/${post.shortCode}` : '');
      likes.push(post.likesCount || 0);
      comments.push(post.commentsCount || 0);
      totalLikes += (post.likesCount || 0);
      totalComments += (post.commentsCount || 0);
      postCount++;
      dates.push(post.timestamp ? new Date(post.timestamp).toISOString().split('T')[0] : (post.takenAtTimestamp ? new Date(post.takenAtTimestamp * 1000).toISOString().split('T')[0] : ''));
      locations.push(post.locationName || post.location?.name || '');
      const postType = post.type || (post.isVideo ? 'video' : (post.childPosts ? 'carousel' : 'image'));
      types.push(postType);

      // Extract media URLs - separate images and videos
      if (post.videoUrl) {
        videoUrlsList.push(post.videoUrl);
      } else if (post.displayUrl) {
        imageUrlsList.push(post.displayUrl);
      } else if (post.imageUrl) {
        imageUrlsList.push(post.imageUrl);
      }
      // For carousel posts, grab ALL child media
      if (post.childPosts && Array.isArray(post.childPosts)) {
        for (const child of post.childPosts) {
          if (child.videoUrl) videoUrlsList.push(child.videoUrl);
          else if (child.displayUrl) imageUrlsList.push(child.displayUrl);
          else if (child.imageUrl) imageUrlsList.push(child.imageUrl);
        }
      }
      // Also check sidecarItems (alternate carousel key)
      if (post.sidecarItems && Array.isArray(post.sidecarItems)) {
        for (const side of post.sidecarItems) {
          if (side.videoUrl) videoUrlsList.push(side.videoUrl);
          else if (side.displayUrl) imageUrlsList.push(side.displayUrl);
        }
      }

      // Extract @mentions from caption
      const mentionMatches = (post.caption || '').match(/@[\w.]+/g) || [];
      mentionMatches.forEach(m => allMentions.add(m));
    }

    recentCaptions = captions.join(' | ');
    const allText = captions.join(' ');
    const hashMatches = allText.match(/#[\w]+/g) || [];
    hashtags = [...new Set(hashMatches)].join(', ');
    postUrls = urls.filter(u => u).join(', ');
    postLikes = likes.join(', ');
    postComments = comments.join(', ');
    postDates = dates.filter(d => d).join(', ');
    postLocations = [...new Set(locations.filter(l => l))].join(', ');
    postTypes = types.join(', ');
  }

  // Calculate engagement rate
  const followers = p.followersCount || 0;
  let engagementRate = 0;
  if (followers > 0 && postCount > 0) {
    engagementRate = Math.round(((totalLikes + totalComments) / postCount / followers) * 10000) / 100;
  }

  // Extract contact info from bio
  const bio = p.biography || '';
  const emailMatch = bio.match(/[\w.+-]+@[\w-]+\.[\w.]+/g);
  const phoneMatch = bio.match(/(?:\+?\d{1,3}[-.\s]?)?\(?\d{2,4}\)?[-.\s]?\d{3,4}[-.\s]?\d{3,4}/g);
  const emailInBio = emailMatch ? emailMatch[0] : '';
  const phoneInBio = phoneMatch ? phoneMatch[0] : '';

  enriched.push({
    json: {
      username: p.username,
      platform: 'instagram',
      full_name: p.fullName || '',
      bio: bio.substring(0, 500),
      follower_count: followers,
      following_count: p.followsCount || 0,
      post_count: p.postsCount || 0,
      is_verified: p.verified || false,
      is_business: p.isBusinessAccount || false,
      business_category: p.businessCategoryName || p.categoryName || '',
      external_url: p.externalUrl || '',
      profile_pic_url: p.profilePicUrl || p.profilePicUrlHD || '',
      email_in_bio: emailInBio,
      phone_in_bio: phoneInBio,
      engagement_rate: engagementRate + '%',
      recent_captions: recentCaptions.substring(0, 2000),
      hashtags: hashtags.substring(0, 500),
      mentions: [...allMentions].join(', ').substring(0, 500),
      recent_post_urls: postUrls.substring(0, 1500),
      recent_post_likes: postLikes,
      recent_post_comments: postComments,
      recent_post_dates: postDates,
      recent_post_locations: postLocations.substring(0, 500),
      recent_post_types: postTypes,
      image_urls: imageUrlsList.join(', '),
      video_urls: videoUrlsList.join(', '),
      avg_likes: postCount > 0 ? Math.round(totalLikes / postCount) : 0,
      avg_comments: postCount > 0 ? Math.round(totalComments / postCount) : 0,
      scrape_date: new Date().toISOString().split('T')[0],
      seed_account: seed.seed_account,
      seed_type: seed.seed_type,
      profile_url: p.url || `https://instagram.com/${p.username}`
    }
  });
}

return enriched.length > 0 ? enriched : [{ json: { _empty: true } }];
